import React from "react";
import {
  AbsoluteFill,
  interpolate,
  useCurrentFrame,
  Easing,
} from "remotion";

const Caption: React.FC<{ text: string; startFrame: number; endFrame: number }> = ({
  text,
  startFrame,
  endFrame,
}) => {
  const frame = useCurrentFrame();
  const progress = interpolate(frame, [startFrame, startFrame + 10], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
  const visible = frame >= startFrame && frame < endFrame;

  if (!visible) return null;

  return (
    <div
      style={{
        position: "absolute",
        bottom: 200,
        width: "100%",
        textAlign: "center",
        opacity: progress,
        transform: `scale(${interpolate(progress, [0, 1], [0.8, 1])})`,
        fontSize: 80,
        fontFamily: "sans-serif",
        color: "#ffffff",
        fontWeight: "bold",
      }}
    >
      {text}
    </div>
  );
};

export const MyVideo: React.FC = () => {
  const frame = useCurrentFrame();
  const titleOpacity = interpolate(frame, [0, 30], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.quad),
  });

  return (
    <AbsoluteFill style={{ backgroundColor: "#1a1a2e" }}>
      <div
        style={{
          position: "absolute",
          top: 300,
          width: "100%",
          textAlign: "center",
          opacity: titleOpacity,
          fontSize: 120,
          fontFamily: "sans-serif",
          color: "#ffffff",
          fontWeight: "bold",
        }}
      >
        Hello
      </div>
      <Caption text="one" startFrame={120} endFrame={180} />
      <Caption text="two" startFrame={180} endFrame={240} />
      <Caption text="three" startFrame={240} endFrame={300} />
    </AbsoluteFill>
  );
};

